import CryptoJS from 'crypto-js'

const AES_KEY = 'ANM23@*EK0T7RLV!'

function replaceCoinW(str) {
    return String(str)
        .replaceAll('coin_w', 'bingking')
        .replaceAll('coin_W', 'bingking')
        .replaceAll('COIN_W', 'bingking')
        .replaceAll('COINW', 'bingking')
        .replaceAll('coinw', 'bingking')
}

// Java: AES/ECB/PKCS5Padding（CryptoJS: ECB + Pkcs7）
function aesEncryptEcbPkcs5(plainText, key = AES_KEY) {
    const keyWordArray = CryptoJS.enc.Utf8.parse(key)
    const encrypted = CryptoJS.AES.encrypt(plainText, keyWordArray, {
        mode: CryptoJS.mode.ECB,
        padding: CryptoJS.pad.Pkcs7
    })
    return encrypted.toString()
}

function aesDecryptEcbPkcs5(cipherTextBase64, key = AES_KEY) {
    const keyWordArray = CryptoJS.enc.Utf8.parse(key)
    const decrypted = CryptoJS.AES.decrypt(cipherTextBase64, keyWordArray, {
        mode: CryptoJS.mode.ECB,
        padding: CryptoJS.pad.Pkcs7
    })
    return CryptoJS.enc.Utf8.stringify(decrypted)
}

function normalizeCipherText(input) {
    const trimmed = String(input ?? '').trim()
    if (!trimmed) return trimmed

    // 去掉所有空白（空格/换行/tab），兼容 `3<base64>` / `3 <base64>` / 多行 Base64
    const compact = trimmed.replace(/\s+/g, '')

    // 兼容：前缀为版本/类型数字（常见 1~2 位），后面才是 Base64
    const m = compact.match(/^(\d{1,2})([A-Za-z0-9+/=]+)$/)
    if (m) {
        const candidate = m[2]
        if (candidate.length % 4 === 0) return candidate
    }

    return compact
}

/**
 * 对齐网关响应加密：
 * String(JSON) -> replaceCoinW -> URLEncoder.encode -> AES(ECB/PKCS5Padding) -> Base64
 * @param {any} responseBody 下游原始响应（对象或字符串）
 * @param {string} key 16位AES key
 * @returns {string} Base64密文字符串
 */
export function encryptGatewayResponse(responseBody, key = AES_KEY) {
    const raw = typeof responseBody === 'string' ? responseBody : JSON.stringify(responseBody)
    const replaced = replaceCoinW(raw)
    // 对齐 Java URLEncoder.encode（空格会变 +）
    const urlEncoded = encodeURIComponent(replaced).replace(/%20/g, '+')
    return aesEncryptEcbPkcs5(urlEncoded, key)
}

/**
 * 对齐网关响应解密：
 * Base64 -> AES解密 -> URLDecode(兼容 + 为空格) -> JSON.parse(失败则返回字符串)
 * @param {string} cipherText Base64密文字符串
 * @param {string} key 16位AES key
 * @returns {any} 对象/字符串
 */
export function decryptGatewayResponse(cipherText, key = AES_KEY) {
    const normalizedCipherText = normalizeCipherText(cipherText)
    if (!normalizedCipherText) {
        throw new Error('密文不能为空')
    }

    const decrypted = aesDecryptEcbPkcs5(normalizedCipherText, key)
    if (!decrypted) {
        throw new Error('AES解密失败，请检查密文或密钥')
    }

    // Java URLEncoder.encode 会把空格变成 +，这里先还原再 decodeURIComponent
    const normalized = decrypted.replace(/\+/g, '%20')
    const decoded = decodeURIComponent(normalized)

    try {
        return JSON.parse(decoded)
    } catch (error) {
        return decoded
    }
}

